var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제1 방위선, 거점 기지","JPN":"人類統合防衛軍第1防衛線、拠点基地","ENG":"Base, United Humankind Defense Force's 1st Defense Line","TWN":"人類共同保衛軍第一防線基地"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"아포리아 공략 작전 후, 5개월 뒤","JPN":"アポリア攻略作戦から5か月後","ENG":"5 months after Operation Aporia","TWN":"攻陷阿波利亞後經過5個月"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"사령관님, 현 시간부로 델타 세븐은 패스파인더 분대로 인원을 재편성.","JPN":"司令官、現時刻よりデルタセブンはパスファインダー分隊として人員を再編成。","ENG":"Commander, Delta Seven has been reassigned to the Pathfinder Squad as of this moment.","TWN":"司令官，第七三角洲部隊開拓者分隊，已重新進行人員整頓。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"물자 준비 및 항해에 필요한 모든 준비를 마쳤습니다.","JPN":"物資の用意および航海に必要な準備をすべて終わらせましたことを。","ENG":"All preparations required for the voyage, including supplies, are complete.","TWN":"已完成物資籌備及航行所需的一切準備。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"이에 보고드리겠습니다!","JPN":"ここに報告いたします！","ENG":"Reporting as ordered!","TWN":"以上，報告完畢！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"반드시 가야 하겠나, 소령?","JPN":"どうしても行くのか、少佐？","ENG":"Must you go, Major?","TWN":"一定要走嗎，少校？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"아직 우리 세계는 아포리아 사태 때 입은 상처를 완전히 회복하지 못했어.","JPN":"まだ私たちの世界はアポリアによる傷が完全に癒えていない。","ENG":"Our world has not yet fully recovered from the wounds caused by the Aporia insident.","TWN":"我們的世界還沒能從阿波利亞事件中完全恢復。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"인류의 결집을 위해서는 자네들과 같은 영웅의 힘이 반드시 필요하네.","JPN":"人類結束のためには、君たちのような英雄の力が不可欠だ。","ENG":"To unite mankind, a hero like yourself is crucial.","TWN":"需要像你們這樣的英雄來招聚大家。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"아니요.","JPN":"いいえ。","ENG":"I think otherwise, sir.","TWN":"不。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"믿기 힘드시겠지만, 제 눈에 깃든 고유 무장 및 아이기스함은 그 존재 자체만으로 이 세계의 침식률을 끌어올릴 겁니다.","JPN":"信じ難いことかと思いますが、私の眼に移植された固有武装およびアイギス艦は存在しているだけで、この世界の侵食率を大きく引き上げてしまいます。","ENG":"It may be hard to believe, but the Unique Gear in my right eye and the existence of Aegis will only increase the Corruption rate of this world.","TWN":"聽起來可能會讓人難以相信，但我眼中的這個專屬裝備，以及埃癸斯的存在，會提高我們世界的侵蝕率。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그렇게 되면, 머지않아 아포리아 사태와 같은 일이 또 발생하겠죠.","JPN":"そうなったら、そう遠くない将来、アポリア事件のようなことが再び起きてしまうでしょう。","ENG":"If that happens, another crisis like Aporia is bound to happen in the near future.","TWN":"那樣的話，不用多久，就又會發生與阿波利亞事件一樣的事情。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"그럼 우리 세계는 멸망을 피할 수가 없다는 말인가?","JPN":"それじゃ、私たちの世界は滅亡を避けられないということか？","ENG":"Are you saying that our world's end is inevitable?","TWN":"你是說我們的世界無法逃脫滅亡的命運嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"이론 상으로는 그렇습니다.","JPN":"理論的にはそうです。","ENG":"In theory, yes, that is correct.","TWN":"理論上是這樣沒錯。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그 안토노프라는 자가 제시했던 이론에서는 그렇죠.","JPN":"あのアントノフという者が話していた理論だとそうです。","ENG":"At least according to Antonov's theory.","TWN":"至少在那個安東諾夫提出的理論中是這樣的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"그게 무슨?","JPN":"どういう意味だ？","ENG":"What?","TWN":"你的意思是？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"이번 사태로 분명해진 건, <color=#ffd34c>한 가지</color>밖에 없습니다.","JPN":"今回の事件で明確になったのは、<color=#ffd34c>一つ</color>だけです。","ENG":"<color=#ffd34c>One thing</color> has been made clear to me from this crisis.","TWN":"經過這次事件，可以確認的只有<color=#ffd34c>一件事</color>。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"멸망해가는 세계의 <color=#ffd34c>내부</color>에서는 멸망을 막을 수 없다는 거죠.","JPN":"滅亡していく世界において、<color=#ffd34c>内部</color>からはそれを阻止できないということです。","ENG":"That, in a collapsing world, there is nothing that can be done to stop it <color=#ffd34c>from within</color>.","TWN":"處在瀕臨滅亡的世界<color=#ffd34c>內部</color>，是無法阻止滅亡的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"따라서 이 항해는 지금까지와는 <color=#ffd34c>다른 길을 찾기 위한</color> 여정입니다.","JPN":"つまり、この航海はこれまでとは<color=#ffd34c>異なる方法を見つけるための</color>旅なんです。","ENG":"Thus, this voyage is to <color=#ffd34c>find another way</color> to stop it.","TWN":"因此，這次航行是為了尋找與以往<color=#ffd34c>不同的道路</color>。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"얼마가 걸릴지, 그 앞에 어떤 시련이 기다리고 있을지 전혀 알 수 없지만…….","JPN":"どれほど時間がかかるか、その先どんな試練が待っているかは全くわかりませんが……","ENG":"I do not know how long it will take, or what trials await me in the future...","TWN":"雖然不知道會花多久時間，也不知道前面會有怎樣的考驗等著我們……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"우린 길을 찾아 낼 겁니다.","JPN":"私たちは方法を見つけてみせます。","ENG":"Nevertheless, we will find a way.","TWN":"但我們會找到一條路。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"안토노프 말에 따르면, 다행히 고심도의 세계들은 이곳과 시간의 흐름이 다르다고 하더군요.","JPN":"アントノフによると、幸い高深度の世界はこちらとは時間の流れが異なるようです。","ENG":"According to Antonov, the flow of time in the hyperdepths is different from here.","TWN":"按照安東諾夫的理論，高深度的世界和這裡的時間流動是不一樣的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"어쩌면 우리 세계가 멸망하기 전에 저희가 길을 찾아 낼 수 있을지도 모를 일이죠.","JPN":"もしかすると、私たちの世界が滅ぶより先に方法を見つけられるかもしれません。","ENG":"Perhaps we will find an answer before our world meets its end.","TWN":"也許在我們的世界毀滅之前，能夠找到出路。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"하지만……","JPN":"しかし……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"하지만 그건 자네들의 <color=#ffd34c>시간</color>을 대가로 한 항해 아닌가?","JPN":"それは君たちの<color=#ffd34c>時間</color>を犠牲にする航海だろう？","ENG":"But at what cost? The price of this voyage is all your <color=#ffd34c>time</color>, is it not?","TWN":"但這不是以你們的<color=#ffd34c>時間</color>為代價的航行嗎?"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"<color=#ffd34c>좌표 축 고정 장치</color>를 이곳에 설치해두고 가겠습니다.","JPN":"<color=#ffd34c>座標軸固定装置</color>をこちらに置いていきます。","ENG":"We will set up the <color=#ffd34c>coordinate axis fixture device</color> here before we leave.","TWN":"離開之前，我會在這裡設置一個<color=#ffd34c>坐標軸固定裝置</color>。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"호출하신다면, 언제든 워프 마커를 통해서 복귀하겠습니다.","JPN":"呼び出しがあれば、いつでもワープマーカーを使って復帰します。","ENG":"If you call, we will return using the warp marker.","TWN":"收到呼叫，我們會隨時透過傳送記號回來。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"반드시요.","JPN":"必ずです。","ENG":"No matter what.","TWN":"一定會的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"전 대원, 그렇게 해서 우리의 항해가 결정되었습니다.","JPN":"隊員の皆さん、というわけで私たちの航海が決定しました。","ENG":"All units, our voyage has been set.","TWN":"全體隊員，我們的航行就這樣定下來了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"우리 세계가 멸망하기 전까지, 우리는 패스파인더로서 반드시 길을 찾아내야만 합니다.","JPN":"この世界が滅ぶ前に、私たちはパスファインダーとして必ず方法を見つけ出さなければなりません。","ENG":"As Pathfinders, we must find a way before our world collapses.","TWN":"在我們世界滅亡之前，作為開拓者我們一定要找到一條出路。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"따라서 지금 이 순간부터는 미래에 대해서 아무것도 보장해드릴 수 없습니다.","JPN":"だから今この瞬間から、その先は何も保証はできません。","ENG":"As of now, I cannot guarantee what the future might hold.","TWN":"並且，從現在開始，未來的一切都將無法保障。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그럼에도…… 묻겠습니다.","JPN":"それでも……お聞きします。","ENG":"Nevertheless... I ask you all.","TWN":"我想問你們，就算如此……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"여러분들은 저와 함께 이 길을 가주시겠습니까?","JPN":"皆さんは私と共に来てくれますか？","ENG":"Will you join me on this journey into the unknown?","TWN":"你們是否願意和我一起踏上這條路？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"물론이지, 소령!","JPN":"もちろんだぜ、少佐！","ENG":"Of course, Major!","TWN":"那是當然的，少校！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"줄곧 새로운 세계로의 여행을 꿈꿔왔다고! 지금이 바로 그때 아니겠어?","JPN":"ずっと新しい世界への旅を夢見ていたんだ！　今がそのチャンスだろう？","ENG":"I've always dreamed about journeying to new worlds! What better time than now?","TWN":"我一直夢想著去一個全新的世界旅行！還有什麼比現在更好的時間！？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"하아, 정말이지. 레베카 양은 단순해도 너무 단순하네요.","JPN":"はあ、まったく。レベッカさんはあまりにも単純すぎます。","ENG":"*Sigh* Really, Rebecca? You're as simple as simple can get.","TWN":"哀，蕾貝卡還真是過於單純呢。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"이건 피크닉 같이 가벼운 여행이 아니라고요.","JPN":"これはピクニックのような、軽いお出かけじゃないんですよ。","ENG":"This isn't some picnic, you know?","TWN":"這可不是輕鬆愉快的野餐旅行喔。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"뭐야, 그럼 칼잡이 너는 왜 소령을 따라가겠다는 건데?","JPN":"何だよナイフ使い、じゃあお前は何で少佐についていくんだ？","ENG":"What? Then why did you decide to follow her, swordie?","TWN":"什麼，那你為什麼要跟著少校？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"그야, 저는 우리 소령님께 아직 받지 못한 보수가 잔~뜩 있단 말이죠.","JPN":"それはほら、私には少佐にまだ貰えてない報酬がた～～くさん残っていますからね。","ENG":"Well, that's because she still owes me a lot of money.","TWN":"這個嘛，自然是少校還欠我很大～一筆報酬囉。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"그걸 받아낼 때까진 뭐, 계속 붙어 다닐 예정이에요.","JPN":"それが全部回収できるまでは、まだまだ離れるわけにはいきませんよ。","ENG":"Until I get every penny of it, I'm staying by her side.","TWN":"在我拿到報酬之前，只能繼續跟著她。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"그쵸, 소령님?","JPN":"ですよね、少佐？","ENG":"Isn't that right, Major?","TWN":"是吧，少校？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"크읏, 마음 같아서는 거절하고 싶지만.","JPN":"くっ、断ってやりたい気持ちは山々ですが。","ENG":"Kgh, I would love to say no, but...","TWN":"咳，雖然我很想拒絕。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"전력이 부족한 관계로, 특별히 승선을 허락해드리죠, 시영 씨.","JPN":"戦力が不足している関係上、特別に乗船を許可してあげます、シノンさん。","ENG":"Since we need every help we can get, I'll especially allow you onboard, Shiyoung.","TWN":"但因為缺乏戰力的關係，就特准你上船吧，時雨。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"헤헷, 서로 볼 꼴 못 볼꼴 다 본 사이인데, 이제와서 왜 그래요, 카린 양?","JPN":"へへっ、お互いの長所も短所も全部見てきた仲じゃないですか、今更ですよ、カリンさん？","ENG":"He heh, what's the matter, Karin? We've already been through thick and thin together.","TWN":"嘿嘿！我們都已經坦誠以待了，你卻這樣對我，卡琳？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"이래봬도 저만한 프로페셔널, 꽤 찾기 힘들다고요?","JPN":"なんだかんだ言っても私ほどのプロフェッショナルは……そういませんよ？","ENG":"It's hard to find someone as professional as me, you know?","TWN":"像我這樣的專業人士，可是打著燈籠都很難找的喔？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"나는 이곳에 남을게.","JPN":"僕はここに残るよ。","ENG":"I'll stay here.","TWN":"我……我就留在這裡了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"이 세계에 남아 있는 고치를 관리할 사람이 필요할 테니까 말이야.","JPN":"この世界に残っている繭を管理する人も必要だろうしな。","ENG":"There needs to be someone who can look after the cocoons in the world.","TWN":"這個世界還需要有人管理剩下的繭。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"나도 마찬가지야.","JPN":"アタシも。","ENG":"Same here.","TWN":"我也是。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"너희들이 귀환할 수 있는 워프 마커를 관리해줄 사람은 이젠 나밖에 없겠지.","JPN":"アンタたちが帰還するためのワープマーカーを管理できる人はもうアタシしかいないしね。","ENG":"I'm the only one who can maintain the warp marker for your return.","TWN":"現在除了我以外，應該沒有人能夠維護你們的傳送記號吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"알겠습니다. 두 분은 남아서 우리 세계의 복구를 위해 힘써주세요.","JPN":"わかりました。お二方はここに残って、私たちの世界の復旧に努めてください。","ENG":"Understood. The two of you stay here and help restore our world to its former glory.","TWN":"我明白了，請你們二位留下來為恢復我們的世界而努力。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"언젠가는, 언젠가는 다시 볼 날이 있을 겁니다. 반드시.","JPN":"いつかは、いつかはまた会えますから。きっと。","ENG":"I'm confident that the day will come when we meet again.","TWN":"總有一天，總有一天我們會再見面的，就這麼說定了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"걱정 마, 너희들이 돌아올 때쯤 되면, 꽤 살만한 세계를 만들어 놓을 테니까.","JPN":"心配しないで。アンタたちが帰ってくる頃には悪くない世界にしておくから。","ENG":"Don't worry. By the time you're all back, this world will look even better than what you remember.","TWN":"放心吧，當你們回來的時候，我們會創造一個相當適合居住的世界。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"전 대원! 이 작전에는 우리 세계의 운명이 달려 있습니다.","JPN":"隊員の皆さん！　この作戦には私たちの世界の運命がかかっています。","ENG":"All units! The fate of our world rests in this operation.","TWN":"全體隊員！這次作戰與我們世界的命運息息相關。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"최우선 목적지는, <color=#ffd34c>관리국</color>이라는 기관이 존재하는 세계!","JPN":"最優先の目的地は、<color=#ffd34c>管理局</color>という機関の存在する世界！","ENG":"Our top objective is reaching the world with an institution called <color=#ffd34c>the Administration</color>!","TWN":"我們的首要目的地是，一個名為<color=#ffd34c>管理局</color>的組織所在的世界！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"우선 그 곳에서부터, 우리 세계의 멸망을 막을 단서를 찾아내는 겁니다!","JPN":"まずはそこから、私たちの世界の滅亡を食い止める手がかりを探り出しましょう！","ENG":"From there, we will find clues that will stop our world's destruction!","TWN":"從那裡開始，我們將著手尋找阻止我們世界毀滅的線索！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그럼, 작전이 시작하는 그 날까지 모두 최상의 컨디션을 유지해주세요!","JPN":"では、作戦開始日まで、皆さん最高のコンディションを維持しておいてください！","ENG":"So until the day the operation starts, please maintain your best conditions!","TWN":"那麼，請各自保持最佳狀態，直到作戰開始的那一天！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};